function ActionButton() {
  const handleClick = e => {
    // e.button is always 0 here — onClick only fires for left button
    console.log('position:', e.clientX, e.clientY);
    if (e.shiftKey) {
      console.log('shift-click — multi-select');
    }
  };

  const handleMouseDown = e => {
    if (e.button === 2) {
      // Middle or right button — doesn't trigger onClick
      console.log('right button pressed:', e.button);
    }
  };

  return (
    <button onClick={handleClick} onMouseDown={handleMouseDown}>
      Click me
    </button>
  );
}

// WRONG — onMouseOver fires repeatedly as cursor moves over child <span>
function HoverCardBad() {
  const [hovered, setHovered] = React.useState(false);
  return (
    <div
      onMouseOver={() => setHovered(true)}
      onMouseOut={() => setHovered(false)}
      style={{ background: hovered ? 'yellow' : 'white' }}
    >
      <span>Inner text</span>  {/* moving onto span triggers flicker */}
    </div>
  );
}

// CORRECT — onMouseEnter/Leave only fire at the outer element boundary
function HoverCard() {
  const [hovered, setHovered] = React.useState(false);
  return (
    <div
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{ background: hovered ? 'yellow' : 'white' }}
    >
      <span>Inner text</span>  {/* no flicker */}
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';

function DraggableBox() {
  const [pos, setPos] = useState({ x: 100, y: 100 });
  const dragging = useRef(false);
  const offset = useRef({ x: 0, y: 0 });

  const handleMouseDown = e => {
    dragging.current = true;
    offset.current = { x: e.clientX - pos.x, y: e.clientY - pos.y };
  };

  useEffect(() => {
    const handleMouseMove = e => {
      if (!dragging.current) return;
      setPos({ x: e.clientX - offset.current.x, y: e.clientY - offset.current.y });
    };
    const handleMouseUp = () => { dragging.current = false; };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, []);

  return (
    <div
      onMouseDown={handleMouseDown}
      style={{
        position: 'absolute',
        left: pos.x,
        top: pos.y,
        width: 80,
        height: 80,
        background: '#3b82f6',
        cursor: 'grab',
      }}
    />
  );
}
// Note: requires window listeners because the cursor can leave the box while dragging.

import { useState, useRef } from 'react';

function DraggableBoxPointer() {
  const [pos, setPos] = useState({ x: 100, y: 100 });
  const offset = useRef({ x: 0, y: 0 });
  const boxRef = useRef(null);

  const handlePointerDown = e => {
    // Capture all pointer events on this element — no window listeners needed
    e.currentTarget.setPointerCapture(e.pointerId);
    offset.current = { x: e.clientX - pos.x, y: e.clientY - pos.y };
  };

  const handlePointerMove = e => {
    // Only fires when pointer is captured (down) because we called setPointerCapture
    if (e.buttons === 0 && e.pointerType === 'mouse') return;
    setPos({ x: e.clientX - offset.current.x, y: e.clientY - offset.current.y });
  };

  const handlePointerUp = e => {
    e.currentTarget.releasePointerCapture(e.pointerId);
  };

  return (
    <div
      ref={boxRef}
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
      style={{
        position: 'absolute',
        left: pos.x,
        top: pos.y,
        width: 80,
        height: 80,
        background: '#22c55e',
        cursor: 'grab',
        touchAction: 'none', // prevent browser scroll from interfering
      }}
    />
  );
}
// Works on mouse, touch, and stylus without any changes.

function DrawingCanvas() {
  const [drawing, setDrawing] = useState(false);

  const stopDrawing = () => setDrawing(false);

  return (
    <canvas
      onPointerDown={() => setDrawing(true)}
      onPointerMove={e => { if (drawing) draw(e.clientX, e.clientY); }}
      onPointerUp={stopDrawing}
      onPointerCancel={stopDrawing}  // phone call, browser scroll, etc.
      onPointerLeave={stopDrawing}   // cursor left the canvas
      style={{ touchAction: 'none' }}
    />
  );
}

import { useState, useRef } from 'react';

function Tooltip({ text, children }) {
  const [visible, setVisible] = useState(false);
  const [coords, setCoords] = useState({ x: 0, y: 0 });
  const ref = useRef(null);

  const show = e => {
    const rect = ref.current.getBoundingClientRect();
    setCoords({ x: rect.left + rect.width / 2, y: rect.top - 8 });
    setVisible(true);
  };

  return (
    <span
      ref={ref}
      onMouseEnter={show}
      onMouseLeave={() => setVisible(false)}
      style={{ position: 'relative', display: 'inline-block' }}
    >
      {children}
      {visible && (
        <span
          role="tooltip"
          style={{
            position: 'fixed',
            left: coords.x,
            top: coords.y,
            transform: 'translate(-50%, -100%)',
            background: '#1f2937',
            color: '#fff',
            padding: '4px 8px',
            borderRadius: 4,
            fontSize: 12,
            pointerEvents: 'none',
            whiteSpace: 'nowrap',
          }}
        >
          {text}
        </span>
      )}
    </span>
  );
}

import { useRef } from 'react';

function CursorTracker() {
  const dotRef = useRef(null);

  const handleMouseMove = e => {
    // Direct DOM mutation — avoids re-rendering on every frame
    if (dotRef.current) {
      dotRef.current.style.transform = `translate(${e.clientX}px, ${e.clientY}px)`;
    }
  };

  return (
    <div
      onMouseMove={handleMouseMove}
      style={{ position: 'fixed', inset: 0, overflow: 'hidden' }}
    >
      <div
        ref={dotRef}
        style={{
          position: 'fixed',
          top: 0,
          left: 0,
          width: 12,
          height: 12,
          background: '#ef4444',
          borderRadius: '50%',
          pointerEvents: 'none',
          translate: '-50% -50%',
        }}
      />
    </div>
  );
}

import { render, screen, fireEvent } from '@testing-library/react';
import userEvent from '@testing-library/user-event';

test('hover shows tooltip', async () => {
  render(<Tooltip text="Save file"><button>Save</button></Tooltip>);
  const btn = screen.getByRole('button', { name: /save/i });

  fireEvent.mouseEnter(btn);
  expect(screen.getByRole('tooltip')).toHaveTextContent('Save file');

  fireEvent.mouseLeave(btn);
  expect(screen.queryByRole('tooltip')).not.toBeInTheDocument();
});

test('reports cursor position on move', () => {
  const onMove = jest.fn();
  render(<div onMouseMove={onMove} data-testid="area" />);

  fireEvent.mouseMove(screen.getByTestId('area'), {
    clientX: 200,
    clientY: 150,
  });

  expect(onMove).toHaveBeenCalledTimes(1);
  expect(onMove.mock.calls[0][0].clientX).toBe(200);
});

test('pointer down starts drag', () => {
  const onDragStart = jest.fn();
  render(<div onPointerDown={onDragStart} data-testid="box" />);

  fireEvent.pointerDown(screen.getByTestId('box'), {
    pointerId: 1,
    pointerType: 'mouse',
    clientX: 50,
    clientY: 50,
  });

  expect(onDragStart).toHaveBeenCalledTimes(1);
});
